const alertFeeds = [
  {
    name: "YOUR_ALERT_NAME",
    url: "YOUR_GOOGLE_ALERTS_RSS_URL",
    category: "Brand Monitoring"
  }
  // ADD MORE FEEDS:
  // ,{ name: "Competitor Alert", url: "YOUR_COMPETITOR_RSS_URL", category: "Competitor Intelligence" }
  // ,{ name: "Industry News", url: "YOUR_INDUSTRY_RSS_URL", category: "Industry Intelligence" }
];
// Get your RSS URL: google.com/alerts → your alert → RSS icon (feed icon at bottom)
return alertFeeds.map(feed => ({ json: feed }));

const rssData  = $input.item.json.data || '';
const feedMeta = $('2. Code — Set Alert Feed URLs').item.json;
const feedName = feedMeta.name     || 'Unknown Feed';
const category = feedMeta.category || 'General';

const entries = [];
const entryRegex = /<entry>(.*?)<\/entry>/gs;
let match;

while ((match = entryRegex.exec(rssData)) !== null) {
  const entry = match[1];

  const titleMatch     = entry.match(/<title[^>]*>(.*?)<\/title>/s);
  const linkMatch      = entry.match(/<link[^>]*href="([^"]+)"/);
  const contentMatch   = entry.match(/<content[^>]*>(.*?)<\/content>/s);
  const summaryMatch   = entry.match(/<summary[^>]*>(.*?)<\/summary>/s);
  const publishedMatch = entry.match(/<published>(.*?)<\/published>/);

  const clean = s => s
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .trim();

  const title      = titleMatch    ? clean(titleMatch[1])   : '';
  const link       = linkMatch     ? linkMatch[1]           : '';
  const rawSummary = contentMatch  ? contentMatch[1] : (summaryMatch ? summaryMatch[1] : '');
  const summary    = clean(rawSummary).substring(0, 600);
  const published  = publishedMatch ? publishedMatch[1] : new Date().toISOString();

  const pubDate   = new Date(published);
  const hoursDiff = (Date.now() - pubDate.getTime()) / 3600000;

  if (hoursDiff <= 48 && title) {
    entries.push({ title, link, summary, published, feedName, category });
  }
}

if (entries.length === 0) {
  return [{ json: { noResults: true, feedName, category } }];
}

return entries.map(e => ({ json: e }));

