const agentOutput = $input.item.json.output || '';
const prev = $('5. IF — Has Results?').item.json;

let analysis = {
  relevance: 5,
  insight: 'Could not analyze this alert.',
  sentiment: 'Neutral',
  action: 'Monitor'
};

try {
  const cleaned = agentOutput
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    analysis.relevance = Math.min(10, Math.max(1, Number(parsed.relevance) || 5));
    analysis.insight   = String(parsed.insight  || analysis.insight);
    analysis.sentiment = String(parsed.sentiment || analysis.sentiment);
    analysis.action    = String(parsed.action    || analysis.action);
  }
} catch(e) { /* keep defaults */ }

const validSentiments = ['Positive', 'Neutral', 'Negative'];
if (!validSentiments.includes(analysis.sentiment)) analysis.sentiment = 'Neutral';

return [{ json: {
  title:              prev.title     || '',
  link:               prev.link      || '',
  summary:            prev.summary   || '',
  published:          prev.published || '',
  feedName:           prev.feedName  || '',
  category:           prev.category  || '',
  analysis_relevance: analysis.relevance,
  analysis_insight:   analysis.insight,
  analysis_sentiment: analysis.sentiment,
  analysis_action:    analysis.action
}}];

const items = $input.item.json.data || [];

const today      = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const todayShort = new Date().toLocaleDateString('en-US', { month:'short', day:'numeric', year:'numeric' });

if (!items.length) {
  return [{ json: {
    emailHtml: `<html><body style="font-family:Arial;padding:20px"><h2>Daily Google Alerts Digest</h2><p>No relevant alerts found today (${todayShort}).</p></body></html>`,
    subject: `Google Alerts Digest - No New Alerts | ${todayShort}`,
    count: 0
  }}];
}

const grouped = {};
items.forEach(item => {
  const cat = item.category || 'General';
  if (!grouped[cat]) grouped[cat] = [];
  grouped[cat].push(item);
});
Object.keys(grouped).forEach(cat =>
  grouped[cat].sort((a,b) => (b.analysis_relevance||0) - (a.analysis_relevance||0))
);

const sentColor = { Positive:'#27ae60', Neutral:'#2980b9', Negative:'#e74c3c' };
const borderCol = r => r >= 8 ? '#e74c3c' : r >= 6 ? '#e67e22' : '#3498db';
const highPri   = items.filter(i => i.analysis_relevance >= 8).length;
const posCount  = items.filter(i => i.analysis_sentiment === 'Positive').length;

let html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:Arial,sans-serif;background:#f0f2f5}
.wrap{max-width:680px;margin:20px auto;border-radius:10px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.12)}
.hdr{background:linear-gradient(135deg,#1a252f,#2c3e50);color:#fff;padding:28px 24px}
.hdr h1{font-size:22px;margin-bottom:6px}
.hdr p{font-size:13px;opacity:.75}
.statsbar{background:#2471a3;display:flex}
.stat{flex:1;padding:10px 16px;color:#fff;font-size:12px;border-right:1px solid rgba(255,255,255,.15)}
.stat:last-child{border-right:none}
.stat strong{font-size:18px;display:block}
.cathead{background:#34495e;color:#fff;padding:10px 20px;font-size:13px;font-weight:bold;letter-spacing:.5px}
.body{background:#fff}
.card{border-left:4px solid #3498db;margin:14px 16px;padding:12px 14px;background:#fafbfc;border-radius:0 6px 6px 0}
.card-title{font-size:14px;font-weight:bold;margin-bottom:5px}
.card-title a{color:#1a252f;text-decoration:none}
.card-meta{font-size:11px;color:#95a5a6;margin-bottom:7px}
.card-insight{font-size:13px;color:#444;line-height:1.5;margin-bottom:8px}
.badges{display:flex;gap:6px;flex-wrap:wrap}
.badge{font-size:11px;padding:3px 9px;border-radius:20px;font-weight:bold;color:#fff}
.b-rel{background:#2980b9}.b-act{background:#e67e22}
.footer{background:#ecf0f1;padding:14px 20px;text-align:center;font-size:11px;color:#7f8c8d}
</style></head><body>
<div class="wrap">
<div class="hdr"><h1>Daily Google Alerts Digest</h1><p>${today}</p></div>
<div class="statsbar">
  <div class="stat"><strong>${items.length}</strong>Total Alerts</div>
  <div class="stat"><strong>${Object.keys(grouped).length}</strong>Categories</div>
  <div class="stat"><strong>${highPri}</strong>High Priority</div>
  <div class="stat"><strong>${posCount}</strong>Positive</div>
</div>
<div class="body">`;

Object.entries(grouped).forEach(([cat, alerts]) => {
  html += `<div class="cathead">${cat} · ${alerts.length} alert${alerts.length>1?'s':''}</div>`;
  alerts.forEach(a => {
    const sc  = sentColor[a.analysis_sentiment] || '#2980b9';
    const bc  = borderCol(a.analysis_relevance || 5);
    const pub = (() => { try { return new Date(a.published).toLocaleString('en-US',{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'}); } catch(e){ return a.published; } })();
    const actualUrl = a.link.includes('google.com/url')
      ? decodeURIComponent(a.link.match(/url=([^&]+)/)?.[1] || a.link)
      : a.link;
    html += `
<div class="card" style="border-left-color:${bc}">
  <div class="card-title"><a href="${actualUrl}" target="_blank">${a.title}</a></div>
  <div class="card-meta">${a.feedName} | ${pub}</div>
  <div class="card-insight">${a.analysis_insight}</div>
  <div class="badges">
    <span class="badge b-rel">${a.analysis_relevance}/10</span>
    <span class="badge" style="background:${sc}">${a.analysis_sentiment}</span>
    ${a.analysis_action ? `<span class="badge b-act">${a.analysis_action}</span>` : ''}
  </div>
</div>`;
  });
});

html += `</div><div class="footer">Powered by n8n + GPT-4.1-mini | YOUR_BRAND_NAME | Relevance 4 or above</div></div></body></html>`;

return [{ json: {
  emailHtml: html,
  subject:   `Google Alerts Digest — ${items.length} Alert${items.length>1?'s':''} | ${todayShort}`,
  count:     items.length
}}];
